"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { useAuth } from "@/context/AuthContext";
import {
  Bed,
  Loader2,
  ArrowLeft,
  Save,
  CheckCircle2,
  AlertCircle,
} from "lucide-react";

interface BedInfo {
  id?: string;
  type: string;
  total: number;
  available: number;
  pricePerDay: number;
}

const DEFAULT_BED_TYPES = ["GENERAL", "ICU", "PRIVATE", "SEMI_PRIVATE"];

export default function HospitalBedsPage() {
  const router = useRouter();
  const { user, isLoading } = useAuth();
  
  const [beds, setBeds] = useState<BedInfo[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState<{ type: "success" | "error"; text: string } | null>(null);

  const fetchBeds = async () => {
    try {
      setLoading(true);
      const res = await fetch("/api/hospitals/beds");
      const data = await res.json();
      if (data.success) {
        // Map existing bed data or initialize defaults if missing
        const existingBeds = data.data.beds as BedInfo[];
        const mappedBeds = DEFAULT_BED_TYPES.map((type) => {
          const match = existingBeds.find((b) => b.type === type);
          return (
            match || {
              type,
              total: 0,
              available: 0,
              pricePerDay: type === "GENERAL" ? 1000 : type === "SEMI_PRIVATE" ? 1800 : type === "PRIVATE" ? 3000 : 5000,
            }
          );
        });
        setBeds(mappedBeds);
      }
    } catch (err) {
      console.error("Error fetching beds:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!isLoading) {
      if (!user || user.role !== "HOSPITAL") {
        router.push("/login");
        return;
      }
      fetchBeds();
    }
  }, [user, isLoading, router]);

  const handleInputChange = (index: number, field: keyof BedInfo, value: number) => {
    const updated = [...beds];
    updated[index] = {
      ...updated[index],
      [field]: value,
    };
    setBeds(updated);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    setMessage(null);

    // Validate: Available cannot exceed Total
    const invalid = beds.some((b) => b.available > b.total);
    if (invalid) {
      setMessage({
        type: "error",
        text: "Validation Error: Available beds cannot exceed the total capacity.",
      });
      setSaving(false);
      return;
    }

    try {
      const res = await fetch("/api/hospitals/beds", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ beds }),
      });
      const data = await res.json();
      if (data.success) {
        setMessage({ type: "success", text: "Bed inventory updated successfully!" });
        fetchBeds();
      } else {
        setMessage({ type: "error", text: data.error || "Failed to update bed details." });
      }
    } catch (err) {
      setMessage({ type: "error", text: "Connection error. Please try again." });
    } finally {
      setSaving(false);
    }
  };

  if (isLoading || loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-surface-secondary">
        <div className="flex flex-col items-center gap-4">
          <Loader2 className="w-10 h-10 text-primary-600 animate-spin" />
          <p className="text-text-secondary text-sm">Loading bed status...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-surface-secondary pb-12">
      {/* Header */}
      <header className="bg-white border-b border-border sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <button
              onClick={() => router.push("/dashboard")}
              className="text-text-muted hover:text-text-primary p-2 -ml-2 rounded-lg hover:bg-surface-secondary transition-colors"
            >
              <ArrowLeft className="w-5 h-5" />
            </button>
            <span className="text-lg font-bold text-text-primary">Beds Manager</span>
          </div>
          <span className="text-xs text-text-muted">Live Inventory</span>
        </div>
      </header>

      {/* Main Roster */}
      <main className="max-w-4xl mx-auto px-4 py-8">
        <div className="mb-6 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
          <div>
            <h1 className="text-2xl font-bold text-text-primary">Live Bed Inventory</h1>
            <p className="text-sm text-text-secondary mt-1">Configure live bed occupancies and daily room charges.</p>
          </div>
          {message && (
            <span
              className={`text-xs px-3.5 py-1.5 rounded-lg border font-semibold flex items-center gap-1.5 ${
                message.type === "success"
                  ? "bg-emerald-50 text-emerald-700 border-emerald-200"
                  : "bg-red-50 text-red-700 border-red-200"
              }`}
            >
              {message.type === "success" ? <CheckCircle2 className="w-4 h-4" /> : <AlertCircle className="w-4 h-4" />}
              {message.text}
            </span>
          )}
        </div>

        <form onSubmit={handleSave} className="space-y-6">
          <div className="grid gap-6">
            {beds.map((bed, index) => (
              <div
                key={bed.type}
                className="bg-white border border-border rounded-2xl p-6 flex flex-col md:flex-row md:items-center md:justify-between gap-6"
              >
                {/* Title */}
                <div className="flex items-center gap-3 md:w-1/4">
                  <div className="w-10 h-10 rounded-xl bg-primary-50 flex items-center justify-center">
                    <Bed className="w-5 h-5 text-primary-600" />
                  </div>
                  <div>
                    <h3 className="font-bold text-text-primary text-sm capitalize">{bed.type.replace("_", " ").toLowerCase()}</h3>
                    <span className="text-xs text-text-muted">Ward Category</span>
                  </div>
                </div>

                {/* Inputs */}
                <div className="flex-1 grid grid-cols-3 gap-4">
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-bold text-text-muted uppercase tracking-wider">Total Capacity</label>
                    <input
                      type="number"
                      required
                      min={0}
                      value={bed.total}
                      onChange={(e) => handleInputChange(index, "total", Math.max(0, parseInt(e.target.value) || 0))}
                      className="w-full text-sm border border-border rounded-xl px-3 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500 font-semibold"
                    />
                  </div>

                  <div className="space-y-1.5">
                    <label className="text-[10px] font-bold text-text-muted uppercase tracking-wider">Available</label>
                    <input
                      type="number"
                      required
                      min={0}
                      value={bed.available}
                      onChange={(e) => handleInputChange(index, "available", Math.max(0, parseInt(e.target.value) || 0))}
                      className={`w-full text-sm border rounded-xl px-3 py-2 bg-white focus:outline-none font-semibold ${
                        bed.available > bed.total
                          ? "border-red-300 text-error focus:border-error"
                          : "border-border text-text-primary focus:border-primary-500"
                      }`}
                    />
                  </div>

                  <div className="space-y-1.5">
                    <label className="text-[10px] font-bold text-text-muted uppercase tracking-wider">Price / Day (₹)</label>
                    <input
                      type="number"
                      required
                      min={0}
                      value={bed.pricePerDay}
                      onChange={(e) => handleInputChange(index, "pricePerDay", Math.max(0, parseInt(e.target.value) || 0))}
                      className="w-full text-sm border border-border rounded-xl px-3 py-2 bg-white text-text-primary focus:outline-none focus:border-primary-500 font-semibold"
                    />
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Action button */}
          <div className="flex justify-end pt-4">
            <button
              type="submit"
              disabled={saving}
              className="px-5 py-2.5 bg-primary-600 hover:bg-primary-700 text-white font-bold rounded-xl transition-all shadow-xs flex items-center gap-2 cursor-pointer disabled:opacity-50"
            >
              {saving ? (
                <>
                  <Loader2 className="w-4 h-4 animate-spin" /> Saving...
                </>
              ) : (
                <>
                  <Save className="w-4 h-4" /> Save Bed Changes
                </>
              )}
            </button>
          </div>
        </form>
      </main>
    </div>
  );
}
